/**
 * Email notification handler for order status changes.
 *
 * Subscribes to order lifecycle events via EventBus and formats
 * email-specific notification content. Integrates with the existing
 * NotificationService by delegating final dispatch to it.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 * - NotificationService for dispatching notifications
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
} from '../events/event-types.js';
import type { OrderStatus } from '../models/order.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  recipient: string;
  subject: string;
  body: string;
  htmlBody: string;
}

/**
 * Status-specific messaging for email notifications.
 */
const STATUS_MESSAGES: Record<OrderStatus, { heading: string; description: string }> = {
  pending: {
    heading: 'Order Received',
    description: 'Your order has been received and is awaiting confirmation.',
  },
  confirmed: {
    heading: 'Order Confirmed',
    description: 'Your order has been confirmed and is being prepared.',
  },
  shipped: {
    heading: 'Order Shipped',
    description: 'Your order has been shipped and is on its way.',
  },
  delivered: {
    heading: 'Order Delivered',
    description: 'Your order has been delivered. Thank you for your purchase!',
  },
  cancelled: {
    heading: 'Order Cancelled',
    description: 'Your order has been cancelled. If you have questions, please contact support.',
  },
};

export class EmailNotificationHandler {
  private logger = new Logger('EmailNotificationHandler');
  private sentEmails: EmailMessage[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Formatting email for new order ${event.order.id}`);

    const itemRows = event.order.items
      .map(
        (item) =>
          `<tr><td>${item.name}</td><td>${item.quantity}</td><td>$${item.unitPrice.toFixed(2)}</td></tr>`,
      )
      .join('');

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    const htmlBody = [
      '<h1>Order Confirmation</h1>',
      `<p>Thank you for your order, ${event.user.name}!</p>`,
      `<p>Order ID: ${event.order.id}</p>`,
      '<table><tr><th>Item</th><th>Qty</th><th>Price</th></tr>',
      itemRows,
      '</table>',
      `<p><strong>Total: $${event.order.total.toFixed(2)}</strong></p>`,
    ].join('');

    this.sendEmail({
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Thank you for your order, ${event.user.name}! Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      htmlBody,
    });
  }

  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Formatting email for order ${event.order.id} status: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const statusInfo = STATUS_MESSAGES[event.newStatus as OrderStatus] ?? {
      heading: 'Order Update',
      description: `Your order status has changed to ${event.newStatus}.`,
    };

    const htmlBody = [
      `<h1>${statusInfo.heading}</h1>`,
      `<p>Order ID: ${event.order.id}</p>`,
      `<p>${statusInfo.description}</p>`,
      `<p>Previous status: ${event.previousStatus}</p>`,
      `<p>New status: ${event.newStatus}</p>`,
    ].join('');

    this.sendEmail({
      recipient: event.order.userId,
      subject: `${statusInfo.heading}: ${event.order.id}`,
      body: `${statusInfo.description} (${event.previousStatus} -> ${event.newStatus})`,
      htmlBody,
    });
  }

  private sendEmail(email: EmailMessage): void {
    this.sentEmails.push(email);
    this.logger.info(`Email queued for ${email.recipient}: ${email.subject}`);
  }

  /**
   * Get status-specific message info for a given order status.
   */
  static getStatusMessage(status: OrderStatus): { heading: string; description: string } {
    return STATUS_MESSAGES[status];
  }

  /**
   * Get all sent emails.
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Get sent emails for a specific recipient.
   */
  getSentEmailsForRecipient(recipient: string): EmailMessage[] {
    return this.sentEmails.filter((e) => e.recipient === recipient);
  }

  /**
   * Get the count of sent emails.
   */
  getSentEmailCount(): number {
    return this.sentEmails.length;
  }

  /**
   * Clear all sent emails (useful for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

